VALUES
  ('diplomatic-9e854390-moex-00366', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '蔡英文總統於110年10月10日出席「中華民國中樞暨各界慶祝110年國慶大會」並發表演說，下列 何者不是演說內容？', '["在臺灣的西南空域，共機常態化的活動，嚴重影響我們的國安及飛安", "在兩岸關係的立場上，維持現狀就是我們的主張", "堅持中華民國臺灣的前途，必須要遵循全體臺灣人民的意志", "兩岸解決分歧，必須透過國際多方對話"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00367', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依臺灣地區與大陸地區人民關係條例，關於臺灣地區人民進入大陸地區，下列敘述何者正確？', '["國家安全局、國防部、法務部調查局及其所屬各級機關未具公務員身分之人員，應向大陸委員會申 請許可，始得進入大陸地區", "直轄市長進入大陸地區應經申請，並經行政院會同大陸委員會、國家安全局、法務部及相關機關組 成之審查會審查許可", "直轄市長進入大陸地區返臺後應向內政部通報", "遇有重大突發事件、影響臺灣地區重大利益或於兩岸互動有重大危害情形者，得經立法院議決由行 政院公告於一定期間內，對臺灣地區人民進入大陸地區，採行禁止、限制或其他必要之處置，立法 院如於會期內1個月未為決議，視為同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00368', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '2021年11月中國共產黨第19屆中央委員會第6次全體會議通過的重要歷史文件是：', '["中共中央關於黨的百年奮鬥重大成就和歷史經驗的決議", "關於建國以來黨的若干歷史問題的決議", "關於若干歷史問題的決議", "中共中央關於中國特色社會主義建設的決議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00369', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '有關中國大陸反分裂國家法中的規定，下列何者錯誤？', '["臺灣問題是中國內戰的遺留問題", "維護國家主權和領土完整是包括臺灣同胞在內的全中國人民的共同義務", "和平統一的可能性完全喪失，國家得採取非和平方式及其他必要措施", "採取非和平方式及其他必要措施，由中共總書記與中央政治局決定和組織實施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00370', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '有關海峽兩岸經濟合作架構協議（ECFA）內容，下列敘述何者錯誤？', '["由財團法人海峽交流基金會與海峽兩岸關係協會於2010年簽署", "後續雙方需要磋商完成服務貿易協議、貨品貿易協議與爭端解決程序協議", "雙方成立「兩岸經濟合作委員會」", "一方終止本協議應以書面通知另一方。雙方應在終止通知發出之日起30日內開始磋商。如磋商未 能達成一致，則本協議自通知一方發出終止通知之日起第90日終止"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00371', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '2022年3月美國總統拜登（Biden）與中國大陸習近平主席視訊通話，拜登總統對中美關係表達「四 不一無意」。關於其內容下列何者錯誤？', '["美國不尋求改變中國體制", "美國不尋求通過強化同盟關係反對中國", "美國不尋求與中國打科技戰", "美國無意同中國發生衝突"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00372', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '將各種不同的選舉制度，區分為「相對多數及絕對多數決」、「半比例代表制」、「比例代表制」等 類型，是根據下列何種標準加以區分？', '["選區規模", "選舉門檻", "選舉規則", "選票結構"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00373', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '下列何者敘述，最符合「單記非讓渡投票」（singlenon-transferablevote,SNTV）此一選舉制度的描述？', '["每一選區僅能選出一位當選人", "臺灣在1949年之後由國民政府引進此一制度", "臺灣目前地方民代選舉仍使用此一制度", "此一制度具有促進中間溫和選舉路線之效果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00374', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '下列敘述何者符合「杜弗傑法則」（Duverger’slaw）關於政黨制度與選舉之主張？', '["絕對多數決傾向產生兩黨制", "比例代表制有助於促進政治和諧", "相對多數決易使第三黨產生代表性不足的情況", "兩輪選舉制易形成多黨聯盟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00375', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-111-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '下列敘述，何者最符合「半總統制」的特徵？', '["總統為虛位元首，總理對國會負責", "總統具有實權，總理由直接民選產生", "總統對國會負責，總理代表行政權", "總統與總理，具有不同的民主正當性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "2ba257b51bb1", "answer_pdf_sha1": "418cf397cc99", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL)
